CREATE TABLE dim_customer (customer_key INT PRIMARY KEY, customer_id VARCHAR(20) UNIQUE, customer_name VARCHAR(100), email VARCHAR(100), signup_date DATE, country VARCHAR(50), loyalty_tier VARCHAR(20), annual_spend DECIMAL(10,2));
CREATE TABLE dim_product (product_key INT PRIMARY KEY, product_id VARCHAR(20) UNIQUE, product_name VARCHAR(100), category VARCHAR(50), subcategory VARCHAR(50), unit_cost DECIMAL(10,2), list_price DECIMAL(10,2), stock_quantity INT);
CREATE TABLE dim_calendar (calendar_key INT PRIMARY KEY, full_date DATE UNIQUE, year_number INT, month_number INT, day_of_month INT);
CREATE TABLE dim_store (store_key INT PRIMARY KEY, store_id VARCHAR(20) UNIQUE, region VARCHAR(20));
CREATE TABLE dim_payment_method (payment_method_key INT PRIMARY KEY, payment_method VARCHAR(20) UNIQUE);
CREATE TABLE fact_sales (transaction_id VARCHAR(20) PRIMARY KEY, customer_key INT, product_key INT, date_key INT, store_key INT, payment_method_key INT, quantity INT, unit_price DECIMAL(10,2), unit_cost DECIMAL(10,2), total_amount DECIMAL(10,2), total_cost DECIMAL(10,2), profit_amount DECIMAL(10,2));
